import docx
from lxml import etree
d = docx.Document('output/settlement-agreement-markup.docx')
W='{http://schemas.openxmlformats.org/wordprocessingml/2006/main}'
XML='{http://www.w3.org/XML/1998/namespace}'

def render(p):
    out=[]
    for el in p._p.iter():
        tag = etree.QName(el).localname
        if tag=='t' and el.text:
            # is it inside ins/del?
            par=el.getparent(); ins=False; de=False
            while par is not None:
                lt=etree.QName(par).localname
                if lt=='ins': ins=True
                if lt=='del': de=True
                par=par.getparent()
            if de: out.append('[-'+el.text+'-]')
            elif ins: out.append('{+'+el.text+'+}')
            else: out.append(el.text)
        elif tag=='delText' and el.text:
            out.append('[-'+el.text+'-]')
    return ''.join(out)

# find paragraphs by content
targets = ['Total Settlement Value','fair market value of each RSU','twenty-one (21) calendar days from the date of receipt','Section 21. Entire Agreement','Section 18. Return of Company Property','Section 19. Cooperation','Section 20. Governing Law','seven (7) day revocation','Tyler Huang, General Counsel','within the State of Oregon','neutral employment reference','Effective Date\" means the eighth']
for t in targets:
    found=False
    for p in d.paragraphs:
        if t in p.text or t in render(p):
            print('### '+t)
            print(render(p)[:600])
            print()
            found=True
            break
    if not found:
        print('### NOT FOUND: '+t); print()
""}

