for p in d.paragraphs:
    r=render(p)
    if 'Defend Trade Secrets Act of 2016. Notwithstanding' in r:
        print(' ', r[:90])
print()
print('=== Signature block tail ===')
for p in d.paragraphs[-14:]:
    r=render(p)
    print(' ', repr(r[:70]))
